from functools import lru_cache
from typing import Literal

from pydantic import Field
from pydantic_settings import BaseSettings, SettingsConfigDict


class Settings(BaseSettings):
    model_config = SettingsConfigDict(
        env_file=".env",
        env_file_encoding="utf-8",
        extra="ignore",
        case_sensitive=False,
    )

    environment: Literal["dev", "staging", "prod"] = "dev"
    log_level: Literal["DEBUG", "INFO", "WARNING", "ERROR", "CRITICAL"] = "INFO"

    database_url: str = Field(default="REDACTED")
    redis_url: str = Field(default="redis://localhost:6379/0")

    applicationinsights_connection_string: str | None = None

    sample_failures_retention_days: int = 30

    azure_tenant_id: str | None = None
    azure_api_client_id: str | None = None
    azure_spa_client_id: str | None = None
    azure_api_scope: str = "user_impersonation"

    auth_dev_bypass: bool = False

    secret_store: Literal["env", "azure_key_vault"] = (
        "env"  # noqa: S105 — mode selector, not a password
    )
    azure_key_vault_url: str | None = None

    @property
    def azure_auth_configured(self) -> bool:
        return bool(self.azure_tenant_id and self.azure_api_client_id)

    @property
    def azure_api_scope_uri(self) -> str | None:
        if not self.azure_api_client_id:
            return None
        return f"api://{self.azure_api_client_id}/{self.azure_api_scope}"


@lru_cache(maxsize=1)
def get_settings() -> Settings:
    return Settings()

@setup_logging.connect  # type: ignore[misc]  # celery signal .connect is unannotated
def _configure_celery_logging(**_kwargs: Any) -> None:
    """Disable Celery's default logging and route worker logs through structlog.

    Connecting any receiver to ``setup_logging`` tells Celery not to configure
    logging itself, so our JSON + PII-redacting processor chain stays in force
    inside the worker exactly as it is in the API.
    """
    configure_logging()


@before_task_publish.connect  # type: ignore[misc]  # celery signal .connect is unannotated
def _inject_request_id(headers: dict[str, Any] | None = None, **_kwargs: Any) -> None:
    """Caller side (FastAPI): stamp the active request_id onto task headers."""
    if headers is None:
        return
    rid = request_id_var.get()
    if rid is not None:
        headers[REQUEST_ID_HEADER] = rid


@task_prerun.connect  # type: ignore[misc]  # celery signal .connect is unannotated
def _restore_request_id(task: Any = None, **_kwargs: Any) -> None:
    """Worker side: restore request_id from the message into the ContextVar.

    Custom headers added in ``before_task_publish`` are exposed as attributes on
    ``task.request`` under the protocol-v2 message format.
    """
    rid = getattr(task.request, REQUEST_ID_HEADER, None) if task is not None else None
    if rid:
        request_id_var.set(rid)


@task_postrun.connect  # type: ignore[misc]  # celery signal .connect is unannotated
def _clear_request_id(**_kwargs: Any) -> None:
    """Worker side: clear the ContextVar so the next task starts uncorrelated."""
    request_id_var.set(None)
